SELECT COUNT(*) AS completed_activities
  FROM maintenance_activities
 WHERE tree_id = 0 AND status = 'completed';

SELECT tree_id
FROM maintenance_activities
WHERE activity_type = 'Pruning';

SELECT COUNT(*) AS assessment_count
FROM health_assessments
WHERE tree_id = 0;

SELECT common_name
FROM genus_species
WHERE native_status = 'native';

SELECT common_name
FROM genus_species
ORDER BY common_name ASC;

SELECT health_rating
FROM health_assessments
WHERE tree_id = 1;

SELECT tree_id
FROM trees
ORDER BY tree_id ASC;

SELECT pest_name, control_methods
FROM pests
WHERE control_methods LIKE '%Pesticide%';
